Implementation file: src/game-of-life.ts
Passing tests: 5 (all tests)
Recent changes: Added reproduction logic - collect dead neighbor candidates, filter those with exactly 3 live neighbors, combine with survivors.

Current implementation:
```typescript
const countLiveNeighbors = (x: number, y: number, alive: Set<string>): number => {
  let count = 0;
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      if (alive.has(`${x + dx},${y + dy}`)) count++;
    }
  }
  return count;
};

export const nextGeneration = (liveCells: number[][]): number[][] => {
  const alive = new Set(liveCells.map(([x, y]) => `${x},${y}`));

  const survivors = liveCells.filter(([x, y]) => {
    const neighbors = countLiveNeighbors(x, y, alive);
    return neighbors >= 2 && neighbors <= 3;
  });

  const deadCandidates = new Set<string>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = `${x + dx},${y + dy}`;
        if (!alive.has(key)) deadCandidates.add(key);
      }
    }
  }

  const born: number[][] = [];
  for (const key of deadCandidates) {
    const [x, y] = key.split(",").map(Number);
    if (countLiveNeighbors(x, y, alive) === 3) {
      born.push([x, y]);
    }
  }

  return [...survivors, ...born];
};
```

Note: The neighbor iteration pattern (dx/dy loops skipping 0,0) appears twice — once in countLiveNeighbors and once in the deadCandidates collection. Consider whether extracting a shared neighbor-coordinate generator would improve clarity. Also consider the type signature — the spec says `type Cell = [number, number]` but we use `number[][]`.

EXPERIMENT MODE: Run autonomously, proceed to next test after completion.

